{
  "$schema": "https://e-menum.net/schemas/module-v1.json",
  "id": "analytics",
  "name": "Analytics Module",
  "version": "0.0.0",
  "status": "stub",
  "description": "İşletme analitiği - satış, menü performansı ve müşteri davranış analizi",

  "type": "feature",
  "category": "analytics",

  "author": {
    "name": "E-Menum Team",
    "email": "dev@e-menum.net"
  },

  "compatibility": {
    "platform": ">=1.0.0",
    "node": ">=20.0.0"
  },

  "dependencies": {
    "modules": ["auth", "organization", "menu", "order"],
    "optional": ["payment"]
  },

  "provides": {
    "services": ["IAnalyticsService", "IReportService"],
    "events": [
      "analytics.report.generated",
      "analytics.insight.created",
      "analytics.alert.triggered"
    ],
    "permissions": [
      "analytics:view",
      "analytics:export",
      "analytics:configure"
    ]
  },

  "tier": {
    "minimum": "starter",
    "features": {
      "starter": ["basic_stats", "daily_reports"],
      "professional": ["basic_stats", "daily_reports", "menu_performance", "weekly_reports"],
      "business": ["basic_stats", "daily_reports", "menu_performance", "weekly_reports", "customer_insights", "export"],
      "enterprise": ["basic_stats", "daily_reports", "menu_performance", "weekly_reports", "customer_insights", "export", "custom_reports", "api_access"]
    }
  },

  "plannedFeatures": [
    "Sales analytics dashboard",
    "Menu performance analysis",
    "Peak hours identification",
    "Customer behavior tracking",
    "Revenue forecasting",
    "Custom report builder",
    "Scheduled reports",
    "Real-time metrics"
  ],

  "estimatedRelease": "Q2 2026"
}
